import{_ as e,o as i,c as l,a2 as r}from"./chunks/framework.CIFdlppq.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"faq/faq.md","filePath":"faq/faq.md","lastUpdated":1782678748000}'),t={name:"faq/faq.md"};function h(s,a,o,n,d,p){return i(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="基础问题" tabindex="-1">基础问题 <a class="header-anchor" href="#基础问题" aria-label="Permalink to &quot;基础问题&quot;">​</a></h2><h3 id="q-ai-verify-mcp-是什么" tabindex="-1">Q: AI-Verify MCP 是什么？ <a class="header-anchor" href="#q-ai-verify-mcp-是什么" aria-label="Permalink to &quot;Q: AI-Verify MCP 是什么？&quot;">​</a></h3><p>A: 一个基于 MCP 协议的 AI 编程验证平台，提供 76 个浏览器自动化和验证工具，帮助你验证 AI 生成的代码是否真的能运行。</p><h3 id="q-支持哪些-ai-客户端" tabindex="-1">Q: 支持哪些 AI 客户端？ <a class="header-anchor" href="#q-支持哪些-ai-客户端" aria-label="Permalink to &quot;Q: 支持哪些 AI 客户端？&quot;">​</a></h3><p>A: 支持所有兼容 MCP 协议的客户端：</p><ul><li>Cursor</li><li>Claude Desktop / Claude Code</li><li>Trae</li><li>Windsurf</li><li>Cline / Roo Code / OpenClaw</li><li>Codex CLI</li><li>Hermes</li><li>CodeArts</li><li>CodeBuddy</li><li>Continue.dev</li></ul><h3 id="q-需要付费吗" tabindex="-1">Q: 需要付费吗？ <a class="header-anchor" href="#q-需要付费吗" aria-label="Permalink to &quot;Q: 需要付费吗？&quot;">​</a></h3><p>A: 完全免费开源，MIT License。</p><h2 id="安装使用" tabindex="-1">安装使用 <a class="header-anchor" href="#安装使用" aria-label="Permalink to &quot;安装使用&quot;">​</a></h2><h3 id="q-安装失败怎么办" tabindex="-1">Q: 安装失败怎么办？ <a class="header-anchor" href="#q-安装失败怎么办" aria-label="Permalink to &quot;Q: 安装失败怎么办？&quot;">​</a></h3><p>A: 常见原因：</p><ol><li>Node.js 版本过低（需 &gt;= 18）</li><li>网络问题导致下载慢，尝试换 npm 镜像</li><li>权限问题，Windows 用管理员身份运行</li></ol><h3 id="q-playwright-下载慢怎么办" tabindex="-1">Q: Playwright 下载慢怎么办？ <a class="header-anchor" href="#q-playwright-下载慢怎么办" aria-label="Permalink to &quot;Q: Playwright 下载慢怎么办？&quot;">​</a></h3><p>A: 设置国内镜像：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PLAYWRIGHT_DOWNLOAD_HOST=https://npmmirror.com/mirrors/playwright</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chromium</span></span></code></pre></div><h3 id="q-怎么确认安装成功" tabindex="-1">Q: 怎么确认安装成功？ <a class="header-anchor" href="#q-怎么确认安装成功" aria-label="Permalink to &quot;Q: 怎么确认安装成功？&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ai-verify-mcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span></span></code></pre></div><p>输出 <code>ok: true</code> 就是成功了。</p><h2 id="功能相关" tabindex="-1">功能相关 <a class="header-anchor" href="#功能相关" aria-label="Permalink to &quot;功能相关&quot;">​</a></h2><h3 id="q-为什么有-76-个工具这么多" tabindex="-1">Q: 为什么有 76 个工具这么多？ <a class="header-anchor" href="#q-为什么有-76-个工具这么多" aria-label="Permalink to &quot;Q: 为什么有 76 个工具这么多？&quot;">​</a></h3><p>A: 因为覆盖了完整的验证流程：浏览器操作、截图、DOM 查询、错误诊断、视觉对比、报告生成等。多不代表复杂，你可以只用常用的几个，其他按需调用。</p><h3 id="q-视觉对比准确吗" tabindex="-1">Q: 视觉对比准确吗？ <a class="header-anchor" href="#q-视觉对比准确吗" aria-label="Permalink to &quot;Q: 视觉对比准确吗？&quot;">​</a></h3><p>A: 基于 pixelmatch 像素级对比，支持阈值调整。0.1 阈值下，细微的渲染差异不会误报。</p><h3 id="q-支持移动端测试吗" tabindex="-1">Q: 支持移动端测试吗？ <a class="header-anchor" href="#q-支持移动端测试吗" aria-label="Permalink to &quot;Q: 支持移动端测试吗？&quot;">​</a></h3><p>A: 支持，可以设置移动端视口和 user-agent。</p><h3 id="q-能测-api-吗" tabindex="-1">Q: 能测 API 吗？ <a class="header-anchor" href="#q-能测-api-吗" aria-label="Permalink to &quot;Q: 能测 API 吗？&quot;">​</a></h3><p>A: 当前主要专注于前端 / 浏览器验证。API 测试支持在规划中。</p><h2 id="安全相关" tabindex="-1">安全相关 <a class="header-anchor" href="#安全相关" aria-label="Permalink to &quot;安全相关&quot;">​</a></h2><h3 id="q-会泄露敏感信息吗" tabindex="-1">Q: 会泄露敏感信息吗？ <a class="header-anchor" href="#q-会泄露敏感信息吗" aria-label="Permalink to &quot;Q: 会泄露敏感信息吗？&quot;">​</a></h3><p>A: 不会。你可以：</p><ol><li>设置 <code>VALIDPILOT_REDACTION=true</code> 启用脱敏</li><li>用 <code>VALIDPILOT_ALLOWLIST</code> 限制可访问域名</li><li>HTTP 模式设置 <code>MCP_API_KEY</code> 认证</li></ol><h3 id="q-能访问内网页面吗" tabindex="-1">Q: 能访问内网页面吗？ <a class="header-anchor" href="#q-能访问内网页面吗" aria-label="Permalink to &quot;Q: 能访问内网页面吗？&quot;">​</a></h3><p>A: 可以。Server 运行在你本地，能访问你本地网络能访问的所有页面。</p><h2 id="开发相关" tabindex="-1">开发相关 <a class="header-anchor" href="#开发相关" aria-label="Permalink to &quot;开发相关&quot;">​</a></h2><h3 id="q-怎么贡献代码" tabindex="-1">Q: 怎么贡献代码？ <a class="header-anchor" href="#q-怎么贡献代码" aria-label="Permalink to &quot;Q: 怎么贡献代码？&quot;">​</a></h3><p>A: 见 <a href="https://github.com/validpilot/ai-verify-mcp/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">贡献指南</a>。</p><h3 id="q-怎么提-bug" tabindex="-1">Q: 怎么提 Bug？ <a class="header-anchor" href="#q-怎么提-bug" aria-label="Permalink to &quot;Q: 怎么提 Bug？&quot;">​</a></h3><p>A: 去 GitHub Issues 提交，尽量附上：</p><ul><li>复现步骤</li><li>期望行为</li><li>实际行为</li><li>环境信息（系统、Node 版本等）</li></ul><h3 id="q-有企业版吗" tabindex="-1">Q: 有企业版吗？ <a class="header-anchor" href="#q-有企业版吗" aria-label="Permalink to &quot;Q: 有企业版吗？&quot;">​</a></h3><p>A: 当前是社区版。有企业需求可以发邮件到 <a href="mailto:validpilot@outlook.com" target="_blank" rel="noreferrer">validpilot@outlook.com</a> 联系。</p><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><h3 id="q-和-playwright-有什么区别" tabindex="-1">Q: 和 Playwright 有什么区别？ <a class="header-anchor" href="#q-和-playwright-有什么区别" aria-label="Permalink to &quot;Q: 和 Playwright 有什么区别？&quot;">​</a></h3><p>A: Playwright 是浏览器自动化引擎，AI-Verify MCP 是基于 Playwright 构建的验证工具集，封装了 76 个高阶工具，专门用于 AI 编程验证场景。</p><h3 id="q-和-cypress-selenium-比怎么样" tabindex="-1">Q: 和 Cypress / Selenium 比怎么样？ <a class="header-anchor" href="#q-和-cypress-selenium-比怎么样" aria-label="Permalink to &quot;Q: 和 Cypress / Selenium 比怎么样？&quot;">​</a></h3><p>A: 定位不同。Cypress/Selenium 是给人写测试用的，AI-Verify MCP 是给 AI 用的验证工具，通过 MCP 协议被 AI 调用。</p>`,47)])])}const q=e(t,[["render",h]]);export{u as __pageData,q as default};
